
USE RENTAL_SYSTEM;

ALTER TABLE biz_house 
ADD COLUMN province_code VARCHAR(6) DEFAULT NULL COMMENT '省份编码' AFTER region_id,
ADD COLUMN province_name VARCHAR(50) DEFAULT NULL COMMENT '省份名称' AFTER province_code,
ADD COLUMN city_code VARCHAR(6) DEFAULT NULL COMMENT '城市编码' AFTER province_name,
ADD COLUMN city_name VARCHAR(50) DEFAULT NULL COMMENT '城市名称' AFTER city_code,
ADD COLUMN district_code VARCHAR(6) DEFAULT NULL COMMENT '区/县编码' AFTER city_name,
ADD COLUMN district_name VARCHAR(50) DEFAULT NULL COMMENT '区/县名称' AFTER district_code;

-- 2. 添加索引以优化查询
CREATE INDEX idx_biz_house_province_code ON biz_house(province_code);
CREATE INDEX idx_biz_house_city_code ON biz_house(city_code);
CREATE INDEX idx_biz_house_district_code ON biz_house(district_code);

